274→async function resolveWorkspaceBootstrapConversation(
275→  deps: ServerDependencies,
276→  workspaceRecord: RecordId<"workspace", string>,
277→): Promise<RecordId<"conversation", string>> {
278→  const [onboardingRows] = await deps.surreal
279→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
280→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
281→      {
282→        workspace: workspaceRecord,
283→      },
284→    )
285→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
286→
287→  if (onboardingRows.length > 0) {
288→    return onboardingRows[0].id;
289→  }
290→
291→  const [latestRows] = await deps.surreal
292→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
293→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
294→      {
295→        workspace: workspaceRecord,
296→      },
297→    )
298→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
299→
300→  if (latestRows.length > 0) {
301→    return latestRows[0].id;
302→  }
303→
304→  const now = new Date();
305→  const conversationRecord = new RecordId("conversation", randomUUID());
306→  await deps.surreal.create(conversationRecord).content({
307→    createdAt: now,
308→    updatedAt: now,
309→    workspace: workspaceRecord,
310→    source: "onboarding",
311→  });
312→  return conversationRecord;
313→}
