 50→  // Shell execution — shared by workspace and orchestrator routes
 51→  const shellExec: ShellExec = async (command, args, cwd) => {
 52→    const proc = Bun.spawn([command, ...args], { cwd, stdout: "pipe", stderr: "pipe" });
 53→    const [stdout, stderr] = await Promise.all([
 54→      new Response(proc.stdout).text(),
 55→      new Response(proc.stderr).text(),
 56→    ]);
 57→    const exitCode = await proc.exited;
 58→    return { exitCode, stdout, stderr };
 59→  };
