 71→  const chatRouteHandler = createChatRouteHandler(deps);
 72→  const mcpHandlers = createMcpRouteHandlers(deps);
 73→  const intentHandlers = createIntentRouteHandlers(deps);
 74→  const intentSubmissionHandler = createIntentSubmissionHandler(deps);
 75→  const tokenEndpointHandler = createTokenEndpointHandler(deps);
 76→  const bridgeExchangeHandler = createBridgeExchangeHandler(deps);
 77→  const observerHandler = createObserverRouteHandler(deps);
 78→  const graphScanHandler = createGraphScanRouteHandler(deps);
 79→  const learningHandlers = createLearningRouteHandlers(deps);
 80→  const policyHandlers = createPolicyRouteHandlers(deps);
 81→  const objectiveHandlers = createObjectiveRouteHandlers(deps);
 82→  const behaviorHandlers = createBehaviorRouteHandlers(deps);
 83→  const anthropicProxyHandler = createAnthropicProxyHandler(deps);
 84→  const proxyTokenHandler = createProxyTokenHandler(deps);
 85→  const spendApiHandlers = createSpendApiHandlers(deps);
 86→  const auditApiHandlers = createAuditApiHandlers(deps);
 87→
 88→  // Orchestrator wiring
 89→  const orchestratorHandlers = wireOrchestratorRoutes({
