  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→import { AgentSessionPanel } from "./AgentSessionPanel";
 14→import { Button } from "../ui/button";
 15→import { Input } from "../ui/input";
 16→import { Badge } from "../ui/badge";
 17→
 18→// ---------------------------------------------------------------------------
 19→// Pure core: view derivation
 20→// ---------------------------------------------------------------------------
 21→
 22→const ASSIGNABLE_STATUSES = new Set(["ready", "todo"]);
 23→
 24→export type AgentStatusViewHidden = { variant: "hidden" };
 25→export type AgentStatusViewAssign = { variant: "assign" };
 26→export type AgentStatusViewActive = {
 27→  variant: "active";
 28→  agentSessionId: string;
 29→  orchestratorStatus: string;
 30→  filesChangedCount: number;
 31→  streamUrl: string;
 32→  startedAt: string;
 33→};
 34→
 35→export type AgentStatusView =
 36→  | AgentStatusViewHidden
 37→  | AgentStatusViewAssign
 38→  | AgentStatusViewActive;
 39→
 40→export type DeriveAgentStatusInput = {
 41→  entityKind: string;
 42→  entityStatus: string;
 43→  agentSession?: AgentSessionSummary;
 44→};
 45→
 46→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 47→  if (input.entityKind !== "task") {
 48→    return { variant: "hidden" };
 49→  }
 50→
 51→  if (input.agentSession) {
 52→    return {
 53→      variant: "active",
 54→      agentSessionId: input.agentSession.agentSessionId,
 55→      orchestratorStatus: input.agentSession.orchestratorStatus,
 56→      filesChangedCount: input.agentSession.filesChangedCount,
 57→      streamUrl: `/api/orchestrator/stream/${encodeURIComponent(input.agentSession.streamId)}`,
 58→      startedAt: input.agentSession.startedAt,
 59→    };
 60→  }
 61→
 62→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 63→    return { variant: "assign" };
 64→  }
 65→
 66→  return { variant: "hidden" };
 67→}
 68→
 69→// ---------------------------------------------------------------------------
 70→// Status badge display
 71→// ---------------------------------------------------------------------------
 72→
 73→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 74→  spawning: "Spawning",
 75→  active: "Working",
 76→  idle: "Idle",
 77→  completed: "Completed",
 78→  aborted: "Aborted",
 79→  error: "Error",
 80→};
 81→
 82→const STATUS_VARIANTS: Record<AgentSessionStatus, "default" | "secondary" | "destructive" | "outline"> = {
 83→  spawning: "outline",
 84→  active: "default",
 85→  idle: "secondary",
 86→  completed: "secondary",
 87→  aborted: "destructive",
 88→  error: "destructive",
 89→};
 90→
 91→function statusLabel(status: AgentSessionStatus): string {
 92→  return STATUS_LABELS[status];
 93→}
 94→
 95→// ---------------------------------------------------------------------------
 96→// Component
 97→// ---------------------------------------------------------------------------
 98→
 99→export function AgentStatusSection({
100→  entityId,
101→  workspaceId,
102→  entityKind,
103→  entityStatus,
104→  agentSession,
105→}: {
106→  entityId: string;
107→  workspaceId: string;
108→  entityKind: EntityKind;
109→  entityStatus: string;
110→  agentSession?: AgentSessionSummary;
111→}) {
112→  const repoPath = useWorkspaceState((s) => s.repoPath);
113→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
114→  const [assigning, setAssigning] = useState(false);
115→  const [assignError, setAssignError] = useState<string | undefined>();
116→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
117→  const [repoPathInput, setRepoPathInput] = useState("");
118→  const [settingRepoPath, setSettingRepoPath] = useState(false);
119→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
120→
121→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
122→
123→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
124→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
125→
126→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
127→
128→  const hasActiveStream = streamUrl !== undefined;
129→
130→  if (initialView.variant === "hidden" && !hasActiveStream) {
131→    return undefined;
132→  }
133→
134→  async function handleAssign() {
135→    if (assigning) return;
136→    setAssigning(true);
137→    setAssignError(undefined);
138→    try {
139→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
140→      const result = await assignAgent(workspaceId, rawTaskId);
141→      setAssignResult(result);
142→    } catch (err) {
143→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
144→    } finally {
145→      setAssigning(false);
146→    }
147→  }
148→
149→  if (hasActiveStream) {
150→    const displayStatus = sessionState.status;
151→    const displayFiles = initialView.variant === "active"
152→      ? initialView.filesChangedCount + sessionState.filesChanged
153→      : sessionState.filesChanged;
154→
155→    const currentSessionId = assignResult?.agentSessionId
156→      ?? (initialView.variant === "active" ? initialView.agentSessionId : "");
157→
158→    return (
159→      <div className="flex flex-col gap-2 px-4">
160→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
161→        <div className="flex items-center gap-2">
162→          <Badge variant={STATUS_VARIANTS[displayStatus]} data-testid="agent-status-badge">
163→            {statusLabel(displayStatus)}
164→          </Badge>
165→          {displayFiles > 0 ? (
166→            <span className="text-xs text-muted-foreground" data-testid="agent-file-count">
167→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
168→            </span>
169→          ) : undefined}
170→        </div>
171→        <AgentSessionPanel
172→          workspaceId={workspaceId}
173→          agentSessionId={currentSessionId}
174→          sessionStatus={displayStatus}
175→          outputEntries={sessionState.outputEntries}
176→          stallWarning={sessionState.stallWarning}
177→          connectionError={sessionState.connectionError}
178→        />
179→        {displayStatus === "idle" ? (
180→          <a
181→            className="text-xs font-medium text-ring hover:underline"
182→            data-testid="agent-review-link"
183→            href={`/review/${encodeURIComponent(currentSessionId)}`}
184→          >
185→            Review
186→          </a>
187→        ) : undefined}
188→      </div>
189→    );
190→  }
191→
192→  if (initialView.variant === "assign") {
193→    const missingRepoPath = repoPath === undefined;
194→
195→    return (
196→      <div className="flex flex-col gap-2 px-4">
197→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
198→        {missingRepoPath ? (
199→          <div className="flex flex-col gap-2 rounded-md border border-border bg-muted p-3" data-testid="agent-repo-path-banner">
200→            <p className="text-xs text-muted-foreground">Repository path is not configured for this workspace. Set it before assigning an agent.</p>
201→            <form
202→              className="flex items-center gap-1.5"
203→              data-testid="agent-repo-path-form"
204→              onSubmit={async (e) => {
205→                e.preventDefault();
206→                const trimmed = repoPathInput.trim();
207→                if (!trimmed || settingRepoPath) return;
208→                setSettingRepoPath(true);
209→                setRepoPathError(undefined);
210→                try {
