 67→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 68→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 69→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
 70→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 71→  const embeddingModelId = requireEnv("EMBEDDING_MODEL");
 72→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 73→
 74→  const surrealUrl = requireEnv("SURREAL_URL");
