149→function parseUnitInterval(value: string, envName: string): number {
150→  const parsed = Number(value);
151→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
152→    throw new Error(`${envName} must be a number between 0 and 1`);
153→  }
154→
155→  return parsed;
156→}
